        { id: "d5q3", pergunta: "De que somos \"membros\", segundo 1 Coríntios 6:15, mencionado no texto?", opcoes: ["Da sinagoga", "De Cristo", "Do império romano", "De uma seita grega"], correta: 1, explicacao: "A resposta correta é: De Cristo." },
        { id: "d5q4", pergunta: "Segundo 1 Coríntios 6:19,20, o que são nossos corpos?", opcoes: ["Propriedade exclusiva nossa", "Templos do Espírito Santo", "Meros instrumentos biológicos", "Irrelevantes para a fé"], correta: 1, explicacao: "A resposta correta é: Templos do Espírito Santo." }
