        { id: "d5q1", pergunta: "Por que carne vendida no mercado poderia, sem que o comprador soubesse, ter sido oferecida a ídolos?", opcoes: ["Porque todo mercado era um templo", "Porque não era mantida separada de outras carnes à venda", "Porque só carne sacrificada era vendida", "Isso nunca acontecia"], correta: 1, explicacao: "A resposta correta é: Porque não era mantida separada de outras carnes à venda." },
        { id: "d5q2", pergunta: "O que Paulo permite quanto a comer carne previamente sacrificada, em casa?", opcoes: ["É proibido em qualquer circunstância", "Pode ser consumida, pois os ídolos não são nada", "Apenas sacerdotes podem comer", "Somente aos sábados"], correta: 1, explicacao: "A resposta correta é: Pode ser consumida, pois os ídolos não são nada." },
        { id: "d5q3", pergunta: "O que era claramente proibido aos cristãos, segundo o texto?", opcoes: ["Comprar qualquer carne no mercado", "Participar de festas e rituais em templos pagãos", "Comer carne de porco", "Trabalhar aos domingos"], correta: 1, explicacao: "A resposta correta é: Participar de festas e rituais em templos pagãos." },
        { id: "d5q4", pergunta: "Segundo o texto, participar de rituais pagãos equivale a quê?", opcoes: ["Um simples costume social", "Ter comunhão com demônios", "Nada de espiritualmente relevante", "Uma forma alternativa de adoração aceitável"], correta: 1, explicacao: "A resposta correta é: Ter comunhão com demônios." }
