        { id: "d6q3", pergunta: "Qual era o problema do jovem rico, segundo Marcos 10:17-22, citado no texto?", opcoes: ["Ele não conhecia a lei", "Ele amava seus bens mais do que a Deus e ao próximo", "Ele era muito religioso", "Ele não tinha família"], correta: 1, explicacao: "A resposta correta é: Ele amava seus bens mais do que a Deus e ao próximo." },
        { id: "d6q4", pergunta: "Segundo o texto, o que pode se tornar uma forma de idolatria?", opcoes: ["Apenas estátuas religiosas", "Qualquer coisa que usurpe a glória que pertence somente a Deus", "Apenas o dinheiro", "Nada além de imagens esculpidas"], correta: 1, explicacao: "A resposta correta é: Qualquer coisa que usurpe a glória que pertence somente a Deus." }
